sys_script_include.script:
function HtmlRenderPageAIStatus()
{
	strHtml = '';

	var aistatus = GetInstanceAIStatus();

	if (IsObject(aistatus) == false)
	{
		return HtmlRenderError('Could not gather details on the AI configuration status on this instance.');
	}

	var aKeys = GetKeys(aistatus);

	for (var nItem = 0; nItem < aKeys.length; nItem++)
	{
		var strKey = aKeys[nItem];
		var item = GetValue(aistatus,strKey);
		if (IsObject(item) == true)
		{
			var strTitle = GetStringValue(GetValue(item,'title'));
			var strInfo = GetStringValue(GetValue(item,'info'));
			var strConfigUrl = GetStringValue(GetValue(item,'config_url'));
			var strDocumentationUrl = GetStringValue(GetValue(item,'documentation_url'));
			var strType = GetStringValue(GetValue(item,'type'));
			var strStatus = GetStringValue(GetValue(item,'status'));

			if (strTitle == '')
			{
				strTitle = strKey;
			}

			strInnerHtml = '<b>' + strTitle + '</b><br/>';
			strInnerHtml += strInfo + '<br/>';

			if (IsValidUrl(strConfigUrl) == true)
			{
				strInnerHtml += HtmlRenderLink(strConfigUrl,'',true);
				strInnerHtml += '<br/>';
			}


			strInnerHtml += '<b>';
			if (strType == 'boolean')
			{
				var bStatus = GetBoolValue(strStatus);
				if (bStatus == true)
				{
					strInnerHtml += '<span style="color: green">OK</span>';
				}
				else
				{
					strInnerHtml += '<span style="color: red">NOT OK</span>';
				}
			}
			else
			{
				//strInnerHtml += '<span style="color: blue">UNKNOWN</span>';
			}
			strInnerHtml += '</b>';

			strHtml += HtmlRenderRoundedBox(strInnerHtml);

		}
	}

	return strHtml;
}
